import React, { useState, useEffect, useRef } from 'react';

const InputArea = ({ currentStep, onSendMessage, isTyping }) => {
  const [inputValue, setInputValue] = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    if (!isTyping && inputRef.current) inputRef.current.focus();
  }, [currentStep, isTyping]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (inputValue.trim() && !isTyping) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  if (!currentStep || isTyping) return null;

  return (
    <div className="w-full flex flex-col items-center gap-10">
      {currentStep.type === 'text' || currentStep.type === 'voice_text' ? (
        <form onSubmit={handleSubmit} className="w-full text-center">
          <input
            ref={inputRef}
            className="w-full bg-transparent text-center text-3xl md:text-4xl text-emerald-600 outline-none placeholder-slate-200 font-light border-b border-slate-100 pb-4"
            placeholder="Type your answer..."
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
          />
          <button 
            type="submit"
            className={`mt-10 px-12 py-4 rounded-full font-semibold transition-all duration-300 ${
              inputValue.length > 0 ? 'bg-slate-800 text-white shadow-xl translate-y-[-2px]' : 'bg-slate-100 text-slate-300'
            }`}
          >
            Continue
          </button>
        </form>
      ) : currentStep.type === 'choice' ? (
        <div className="flex flex-col gap-4 w-full">
          {currentStep.options.map(option => (
            <button
              key={option}
              onClick={() => onSendMessage(option)}
              className="w-full py-5 rounded-2xl border-2 border-slate-100 hover:border-emerald-500 hover:bg-emerald-50 text-xl font-medium text-slate-700 transition-all"
            >
              {option}
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
};

export default InputArea;
